// Function for redeeming a coupon code
function redeemCoupon(couponCode) {
  // Check if the coupon is still valid and not expired
  const coupon = getCouponByCode(couponCode);
  if (!coupon || coupon.expirationDate < Date.now()) {
    return null;
  }

  // Verify that the coupon hasn't been used yet
  if (coupon.used) {
    return null;
  }

  // Mark the coupon as used and apply the discount
  markCouponAsUsed(couponCode);
  const discount = calculateDiscount(coupon);
  applyDiscount(discount);

  return discount;
}